@override
Widget build(BuildContext context) {
  // 1. Read + SUBSCRIBE — Theme/MediaQuery/Provider.of<T> return the value AND
  //    register this widget to rebuild when the ancestor changes.
  final theme = Theme.of(context);
  final size = MediaQuery.of(context).size;

  // 2. Read WITHOUT subscribing — use `listen: false` for one-shot reads.
  //    Common with Provider when you want to call a method but not rebuild.
  final cart = Provider.of<Cart>(context, listen: false);

  // 3. Framework navigation — always via context.
  return FilledButton(
    onPressed: () => Navigator.of(context).push(
      MaterialPageRoute(builder: (_) => const DetailPage()),
    ),
    child: Text('Open', style: theme.textTheme.labelLarge),
  );
}

// BAD — using context after await
void _save() async {
  await api.save();
  // 500 ms have passed. User might have popped this page.
  // context may point to a DEAD Element. Navigator.push crashes.
  Navigator.of(context).pop();     // ❌
}

// GOOD — Flutter 3.7+ added context.mounted for exactly this
void _save() async {
  await api.save();
  if (!context.mounted) return;    // ✅
  Navigator.of(context).pop();
}

// ALSO GOOD — read what you need BEFORE the await
void _save() async {
  final nav = Navigator.of(context);  // capture now, still on tree
  await api.save();
  nav.pop();                          // NavigatorState is not tied to `context`
}

// The lint `use_build_context_synchronously` catches these at edit time.

import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(home: HomePage()));

class HomePage extends StatelessWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context) {
    // Read Theme + MediaQuery via context (walks up the tree).
    final theme = Theme.of(context);
    final width = MediaQuery.of(context).size.width;

    return Scaffold(
      appBar: AppBar(title: const Text('BuildContext demo')),
      body: Center(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text('width: ${width.toStringAsFixed(0)}px',
                style: theme.textTheme.bodyLarge),
            const SizedBox(height: 16),
            FilledButton(
              onPressed: () async {
                // Capture Navigator BEFORE the await gap.
                final nav = Navigator.of(context);
                await Future<void>.delayed(const Duration(milliseconds: 400));
                // context might be gone; nav is fine.
                nav.push(MaterialPageRoute(
                  builder: (_) => const _Detail(),
                ));
              },
              child: const Text('Open Detail (after 400ms)'),
            ),
            const SizedBox(height: 16),
            FilledButton(
              onPressed: () async {
                await Future<void>.delayed(const Duration(milliseconds: 400));
                if (!context.mounted) return;   // guard the async gap
                ScaffoldMessenger.of(context).showSnackBar(
                  const SnackBar(content: Text('back in the tree')),
                );
              },
              child: const Text('SnackBar with mounted check'),
            ),
          ],
        ),
      ),
    );
  }
}

class _Detail extends StatelessWidget {
  const _Detail();
  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Detail')),
    body: const Center(child: Text('back to see the parent context still works')),
  );
}
